          if (hasLocal) {
            await LocalAvatarDB.delete(name);
          }

          // 更新数据：清除URL，保留别名和位置设置
          const data = AvatarManager.getAll()[name] || {};
          AvatarManager.set(name, '', data.offsetX ?? 50, data.offsetY ?? 50, data.scale ?? 150, data.aliases || []);

          // 刷新显示
          await refreshItem(name);
